use serde::Serialize;

/// A single finding from the analyzer, with span relative to input.
#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
pub struct RawFinding {
    pub code: String,
    pub message: String,
    pub span: (usize, usize),
}

/// Detection rule: code + patterns + message prefix
#[derive(Debug, Clone)]
pub struct Rule {
    pub code: &'static str,
    pub patterns: Vec<String>,
    pub message_prefix: &'static str,
}

impl Rule {
    pub fn new(code: &'static str, patterns: Vec<String>, message_prefix: &'static str) -> Self {
        Self {
            code,
            patterns,
            message_prefix,
        }
    }
}

/// CANDIDATE: json
///
/// A pure, deterministic analyzer over a fixed ruleset. Purity is essential:
/// the verifier re-runs `analyze` on the witness and must obtain identical findings.
pub trait ReplayableAnalyzer {
    fn version(&self) -> &str;
    fn rules(&self) -> &[Rule];

    /// Stable digest over the ruleset, binding receipts to the exact rules.
    /// Changing any pattern invalidates receipts computed under old rules.
    fn ruleset_digest(&self) -> String {
        let mut h = blake3::Hasher::new();
        h.update(b"lsp-max-rvd/json/v1\n");
        for rule in self.rules() {
            h.update(rule.code.as_bytes());
            h.update(b"\n");
            for p in &rule.patterns {
                h.update(p.as_bytes());
                h.update(b"\x00");
            }
            h.update(b"\n");
        }
        h.finalize().to_hex().to_string()
    }

    /// Scan input, returning findings in deterministic order (by start, then code).
    /// Spans are relative to input.
    fn analyze(&self, input: &str) -> Vec<RawFinding> {
        let mut findings = Vec::new();
        for rule in self.rules() {
            for pattern in &rule.patterns {
                if pattern.is_empty() {
                    continue;
                }
                let mut start = 0;
                while let Some(pos) = input[start..].find(pattern.as_str()) {
                    let abs = start + pos;
                    findings.push(RawFinding {
                        code: rule.code.to_string(),
                        message: format!("{}: {pattern}", rule.message_prefix),
                        span: (abs, abs + pattern.len()),
                    });
                    start = abs + pattern.len();
                }
            }
        }
        findings.sort_by(|a, b| a.span.0.cmp(&b.span.0).then(a.code.cmp(&b.code)));
        findings
    }
}

/// CANDIDATE: json implementation
pub struct JsonAnalyzer {
    version: String,
    rules: Vec<Rule>,
}

impl JsonAnalyzer {
    pub fn new() -> Self {
        Self {
            version: format!("json-rvd-{}", env!("CARGO_PKG_VERSION")),
            rules: settings_json_rules(),
        }
    }

    /// Construct an analyzer over an explicit ruleset (used in tests).
    pub fn with_rules(version: impl Into<String>, rules: Vec<Rule>) -> Self {
        Self {
            version: version.into(),
            rules,
        }
    }
}

impl Default for JsonAnalyzer {
    fn default() -> Self {
        Self::new()
    }
}

impl ReplayableAnalyzer for JsonAnalyzer {
    fn version(&self) -> &str {
        &self.version
    }
    fn rules(&self) -> &[Rule] {
        &self.rules
    }
}


#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn analyzer_version_is_set() {
        let analyzer = JsonAnalyzer::new();
        assert!(!analyzer.version().is_empty());
    }

    #[test]
    fn ruleset_digest_is_stable() {
        let rules = vec![Rule::new("TEST-001", vec!["pattern".to_string()], "test")];
        let a1 = JsonAnalyzer::with_rules("test-1.0", rules.clone());
        let a2 = JsonAnalyzer::with_rules("test-1.0", rules);
        assert_eq!(a1.ruleset_digest(), a2.ruleset_digest());
    }

    #[test]
    fn analyze_returns_ordered_findings() {
        let rules = vec![Rule::new("TEST-001", vec!["x".to_string()], "found")];
        let analyzer = JsonAnalyzer::with_rules("test", rules);
        let findings = analyzer.analyze("x first x second");
        assert_eq!(findings.len(), 2);
        assert!(findings[0].span.0 < findings[1].span.0);
    }

    #[test] fn deprecated_key_detected() { let i = r#"{"enabledMcpjsonServers": []}"#; assert!(JsonAnalyzer::new().analyze(i).iter().any(|f| f.code == "CCC-JSON-001")); }
    #[test] fn camel_case_hooks_detected() { let i = r#"{"hookEvents": {}}"#; assert!(JsonAnalyzer::new().analyze(i).iter().any(|f| f.code == "CCC-JSON-002")); }
    #[test] fn valid_json_keys_clean() { let i = r#"{"hooks": {}, "mcpServers": {}}"#; assert!(JsonAnalyzer::new().analyze(i).is_empty()); }
}

// ── Hand-coded: settings.json validation ─────────────────────────────────────
// Source: Claude Code settings.json schema — detect deprecated/wrong key names

/// Pattern-scan rules for settings.json key violations.
pub fn settings_json_rules() -> Vec<Rule> {
    vec![
        // CCC-JSON-001: deprecated key names from older Claude Code versions
        Rule::new("CCC-JSON-001", vec![
            "enabledMcpjsonServers".to_string(),
            "disabledMcpjsonServers".to_string(),
            "mcpJsonServers".to_string(),
        ], "Deprecated settings.json key — use mcpServers"),
        // CCC-JSON-002: wrong casing for hook event keys in settings.json
        Rule::new("CCC-JSON-002", vec![
            "hookEvents".to_string(),
            "hook_events".to_string(),
            "pre_tool_use".to_string(),
            "post_tool_use".to_string(),
        ], "Wrong hook key format — use hooks.PreToolUse / hooks.PostToolUse"),
        // CCC-JSON-003: common typo — "permissions" instead of "permissionMode"
        Rule::new("CCC-JSON-003", vec![
            "\"permissions\"".to_string(),
        ], "Unknown key 'permissions' — did you mean permissionMode?"),
    ]
}
